use std::process::{Command, Stdio};
use crate::types::*;



/// Abstract interface for agent backends.
pub trait AgentBackend {
    /// Send a message with context and return the response.
    fn send_message(&self, message: &str, context: &[Message]) -> AgentResponse;

    /// Return the backend name.
    fn name(&self) -> &str;

    /// Whether this backend supports streaming output.
    fn supports_streaming(&self) -> bool { false }
}



/// CLI-based backend that shells out to a command.
pub struct CliBackend {
    pub backend_name: String,
    pub command: String,
    pub args: Vec<String>,
    pub model: Option<String>,
}

impl CliBackend {
    pub fn new(name: &str, command: &str, args: &[&str], model: Option<String>) -> Self {
        Self {
            backend_name: name.to_string(),
            command: command.to_string(),
            args: args.iter().map(|s| s.to_string()).collect(),
            model,
        }
    }
}

impl AgentBackend for CliBackend {
    fn send_message(&self, message: &str, _context: &[Message]) -> AgentResponse {
        let mut cmd = Command::new(&self.command);
        for arg in &self.args {
            cmd.arg(arg);
        }
        if let Some(ref model) = self.model {
            cmd.arg(model);
        }
        cmd.arg(message);
        cmd.stdout(Stdio::piped()).stderr(Stdio::piped());

        match cmd.output() {
            Ok(output) => {
                let content = String::from_utf8_lossy(&output.stdout).to_string();
                AgentResponse {
                    content,
                    model: self.backend_name.clone(),
                    ..Default::default()
                }
            }
            Err(e) => AgentResponse {
                content: format!("Error running {}: {}", self.command, e),
                model: self.backend_name.clone(),
                ..Default::default()
            },
        }
    }

    fn name(&self) -> &str { &self.backend_name }
}


use std::io::{BufRead, Write};

/// Parse a single SSE event line.
/// Returns the data payload if the line starts with "data: ", or None.
pub fn parse_sse_line(line: &str) -> Option<String> {
    let trimmed = line.trim();
    if trimmed == "data: [DONE]" {
        return None;
    }
    if let Some(data) = trimmed.strip_prefix("data: ") {
        Some(data.to_string())
    } else {
        None
    }
}

/// Extract content delta from an SSE JSON payload.
/// Supports OpenAI/OpenRouter format (choices[0].delta.content)
/// and Anthropic format (delta.text).
pub fn extract_content_delta(json_str: &str) -> Option<String> {
    let json: serde_json::Value = serde_json::from_str(json_str).ok()?;
    // OpenAI / OpenRouter format
    if let Some(content) = json.get("choices")
        .and_then(|c| c.get(0))
        .and_then(|c| c.get("delta"))
        .and_then(|d| d.get("content"))
        .and_then(|c| c.as_str()) {
        return Some(content.to_string());
    }
    // Anthropic format
    if let Some(text) = json.get("delta")
        .and_then(|d| d.get("text"))
        .and_then(|t| t.as_str()) {
        return Some(text.to_string());
    }
    None
}

/// Send a streaming request and print output progressively.
/// Returns the complete accumulated response content and token usage.
pub fn send_streaming(
    client: &reqwest::blocking::Client,
    endpoint: &str,
    api_key: Option<&str>,
    body: serde_json::Value,
) -> (String, u64, u64) {
    let mut req = client.post(endpoint)
        .header("Content-Type", "application/json");
    if let Some(key) = api_key {
        req = req.header("Authorization", format!("Bearer {}", key));
    }

    match req.json(&body).send() {
        Ok(resp) => {
            let mut full_content = String::new();
            let reader = std::io::BufReader::new(resp);
            for line in reader.lines() {
                match line {
                    Ok(line) => {
                        if let Some(data) = parse_sse_line(&line) {
                            if let Some(delta) = extract_content_delta(&data) {
                                print!("{}", delta);
                                let _ = std::io::stdout().flush();
                                full_content.push_str(&delta);
                            }
                        }
                    }
                    Err(_) => break,
                }
            }
            println!();
            (full_content, 0, 0)
        }
        Err(e) => {
            (format!("Streaming error: {}", e), 0, 0)
        }
    }
}


/// API-based backend that sends HTTP requests.
pub struct ApiBackend {
    pub backend_name: String,
    pub endpoint: String,
    pub api_key: Option<String>,
    pub model: String,
    pub stream: bool,
}

impl ApiBackend {
    pub fn new(name: &str, endpoint: &str, api_key: Option<String>, model: &str, stream: bool) -> Self {
        Self {
            backend_name: name.to_string(),
            endpoint: endpoint.to_string(),
            api_key,
            model: model.to_string(),
            stream,
        }
    }

    fn build_messages(&self, message: &str, context: &[Message]) -> Vec<serde_json::Value> {
        let mut messages: Vec<serde_json::Value> = context.iter().map(|m| {
            serde_json::json!({
                "role": m.role,
                "content": m.content,
            })
        }).collect();
        messages.push(serde_json::json!({
            "role": "user",
            "content": message,
        }));
        messages
    }
}

impl AgentBackend for ApiBackend {
    fn send_message(&self, message: &str, context: &[Message]) -> AgentResponse {
        let client = reqwest::blocking::Client::new();
        let messages = self.build_messages(message, context);
        let mut body = serde_json::json!({
            "model": self.model,
            "messages": messages,
        });

        if self.stream {
            body["stream"] = serde_json::json!(true);
            let (content, input_tokens, output_tokens) = send_streaming(
                &client,
                &self.endpoint,
                self.api_key.as_deref(),
                body,
            );
            return AgentResponse {
                content,
                input_tokens,
                output_tokens,
                model: self.model.clone(),
                ..Default::default()
            };
        }

        let mut req = client.post(&self.endpoint)
            .header("Content-Type", "application/json");
        if let Some(ref key) = self.api_key {
            req = req.header("Authorization", format!("Bearer {}", key));
        }

        match req.json(&body).send() {
            Ok(resp) => {
                match resp.json::<serde_json::Value>() {
                    Ok(json) => {
                        let content = json["choices"][0]["message"]["content"]
                            .as_str()
                            .unwrap_or("")
                            .to_string();
                        let input_tokens = json["usage"]["prompt_tokens"].as_u64().unwrap_or(0);
                        let output_tokens = json["usage"]["completion_tokens"].as_u64().unwrap_or(0);
                        AgentResponse {
                            content,
                            input_tokens,
                            output_tokens,
                            model: self.model.clone(),
                            ..Default::default()
                        }
                    }
                    Err(e) => AgentResponse {
                        content: format!("JSON parse error: {}", e),
                        model: self.model.clone(),
                        ..Default::default()
                    },
                }
            }
            Err(e) => AgentResponse {
                content: format!("HTTP error: {}", e),
                model: self.model.clone(),
                ..Default::default()
            },
        }
    }

    fn name(&self) -> &str { &self.backend_name }
    fn supports_streaming(&self) -> bool { true }
}

/// Create a backend from configuration.
pub fn create_backend(config: &AgentConfig) -> Box<dyn AgentBackend> {
    match config.backend.as_str() {
        "coro" => Box::new(CliBackend::new("coro", "claude", &[], config.model.clone())),
        "claude-code" => Box::new(CliBackend::new("claude-code", "claude", &[], Some("sonnet".to_string()))),
        "gemini" => Box::new(CliBackend::new("gemini", "gemini", &[], Some("gemini-2.5-flash".to_string()))),
        "claude" => {
            let key = std::env::var("ANTHROPIC_API_KEY").ok().or(config.api_key.clone());
            let model = config.model.clone().unwrap_or_default();
            Box::new(ApiBackend::new("claude", "https://api.anthropic.com/v1/messages", key, &model, config.stream))
        }
        "openai" => {
            let key = std::env::var("OPENAI_API_KEY").ok().or(config.api_key.clone());
            let model = config.model.clone().unwrap_or_default();
            Box::new(ApiBackend::new("openai", "https://api.openai.com/v1/chat/completions", key, &model, config.stream))
        }
        "openrouter" => {
            let key = std::env::var("OPENROUTER_API_KEY").ok().or(config.api_key.clone());
            let model = config.model.clone().unwrap_or_default();
            Box::new(ApiBackend::new("openrouter", "https://openrouter.ai/api/v1/chat/completions", key, &model, config.stream))
        }
        "ollama-api" => Box::new(ApiBackend::new("ollama-api", "http://localhost:11434/api/chat", None, &config.model.clone().unwrap_or_default(), config.stream)),
        "ollama-cli" => Box::new(CliBackend::new("ollama-cli", "ollama", &[], Some("llama3".to_string()))),
        _ => panic!("Unknown backend: {}", config.backend),
    }
}

